local xml2lua = require "xml2lua"
local xmlhandler = require "xmlhandler"

local function parse_soap_request()
    local body = ngx.req.get_body_data()
    if not body then
        ngx.status = 400
        ngx.say("Missing request body")
        ngx.exit(400)
        return
    end
    
    local handler = xmlhandler.Tree:new()
    local parser = xml2lua.parser(handler, true)
    
    -- Enable entity reference parsing
    parser:setEntityResolver(function(name)
        return nil
    end)
    
    local success, err = pcall(function()
        parser:parse(body)
    end)
    
    if not success then
        ngx.status = 400
        ngx.say("Invalid XML: " .. tostring(err))
        ngx.exit(400)
        return
    end
    
    return handler.root
end

local function extract_soap_data(xml_root)
    local soap_data = {}
    
    if xml_root and xml_root.name == "Envelope" then
        local body = xml_root:getChild("Body")
        if body then
            local operation = body.children[1]
            if operation then
                soap_data.operation = operation.name
                soap_data.params = {}
                
                for i, child in ipairs(operation.children or {}) do
                    soap_data.params[child.name] = child.text or ""
                end
            end
        end
    end
    
    return soap_data
end

local function process_soap_request()
    local xml_root = parse_soap_request()
    if not xml_root then return end
    
    local soap_data = extract_soap_data(xml_root)
    
    -- Process the extracted data
    ngx.log(ngx.INFO, "Processing SOAP operation: " .. tostring(soap_data.operation))
    
    -- Example processing
    local response = {
        status = "success",
        operation = soap_data.operation,
        processed_params = soap_data.params
    }
    
    ngx.say(xml2lua.serialize(response))
end

process_soap_request()